INSERT INTO `im_private_message` VALUES (124, 19, 20, '周末带你去钓鱼', 0, 1, '2025-07-22 10:56:48');
INSERT INTO `im_private_message` VALUES (125, 20, 19, '真的吗？太期待了！', 0, 1, '2025-07-22 10:56:48');
INSERT INTO `im_private_message` VALUES (126, 19, 20, '儿子，数学考试怎么样？', 0, 1, '2025-07-24 10:56:48');
INSERT INTO `im_private_message` VALUES (127, 20, 19, '我得了A，爸爸！', 0, 1, '2025-07-24 10:56:48');
INSERT INTO `im_private_message` VALUES (128, 19, 20, '真棒！继续保持', 0, 1, '2025-07-24 10:56:48');
INSERT INTO `im_private_message` VALUES (129, 20, 19, '谢谢爸爸鼓励', 0, 1, '2025-07-24 10:56:48');
INSERT INTO `im_private_message` VALUES (130, 19, 20, '儿子，我教你钓鱼技巧', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (131, 20, 19, '太好了！我想学', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (132, 19, 20, '钓到了几条鱼？', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (133, 20, 19, '三条！爸爸教得好', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (134, 19, 20, '儿子真棒！', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (135, 19, 21, '宝贝，想要什么礼物？', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (136, 21, 19, '想要新的舞蹈鞋，爸爸', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (137, 19, 21, '好的，周末带你去买', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (138, 21, 19, '谢谢爸爸！', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (139, 19, 21, '听说你舞蹈老师表扬你了？', 0, 1, '2025-07-24 10:56:48');
INSERT INTO `im_private_message` VALUES (140, 21, 19, '是的，老师说我跳得很好', 0, 1, '2025-07-24 10:56:48');
INSERT INTO `im_private_message` VALUES (141, 19, 21, '爸爸为你骄傲', 0, 1, '2025-07-24 10:56:48');
INSERT INTO `im_private_message` VALUES (142, 21, 19, '我会更加努力的', 0, 1, '2025-07-24 10:56:48');
INSERT INTO `im_private_message` VALUES (143, 21, 19, '爸爸，周末我能摘草莓吗？', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (144, 19, 21, '当然可以，宝贝', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (145, 21, 19, '爸爸，我摘了满满一篮子草莓！', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (146, 19, 21, '真棒！你是爸爸的好女儿', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (147, 21, 19, '我爱你，爸爸', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (148, 19, 21, '爸爸也爱你', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (149, 20, 21, '妹妹，今天放学一起回家吗？', 0, 1, '2025-07-21 10:56:48');
INSERT INTO `im_private_message` VALUES (150, 21, 20, '好啊，哥哥，等我一下', 0, 1, '2025-07-21 10:56:48');
INSERT INTO `im_private_message` VALUES (151, 20, 21, '我在学校门口等你', 0, 1, '2025-07-21 10:56:48');
INSERT INTO `im_private_message` VALUES (152, 21, 20, '哥哥，我数学题不会做', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (153, 20, 21, '我来教你吧', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (154, 21, 20, '谢谢哥哥！', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (155, 20, 21, '不客气，你舞蹈跳得真好', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (156, 21, 20, '你数学也很棒！', 0, 1, '2025-07-23 10:56:48');
INSERT INTO `im_private_message` VALUES (157, 20, 21, '周末农家乐，我要去钓鱼', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (158, 21, 20, '我要摘草莓', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (159, 20, 21, '我们可以交换，我帮你摘一些草莓', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (160, 21, 20, '我也帮你看鱼竿', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (161, 20, 21, '我们是最好的兄妹', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (162, 21, 20, '是的！', 0, 1, '2025-07-25 10:56:48');
INSERT INTO `im_private_message` VALUES (163, 20, 21, '妹妹，我钓到了三条鱼！', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (164, 21, 20, '哇！好厉害！', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (165, 21, 20, '我摘了好多草莓，给你一些', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (166, 20, 21, '谢谢妹妹，你真好', 0, 1, '2025-07-26 10:56:48');
INSERT INTO `im_private_message` VALUES (167, 14, 15, '明天我去上海出差', 0, 1, '2025-07-14 10:56:48');
INSERT INTO `im_private_message` VALUES (168, 15, 14, '注意安全，需要带什么吗？', 0, 1, '2025-07-14 10:56:48');
INSERT INTO `im_private_message` VALUES (169, 14, 15, '我已经收拾好了，谢谢', 0, 1, '2025-07-14 10:56:48');
INSERT INTO `im_private_message` VALUES (170, 15, 14, '孩子们的事我来安排', 0, 1, '2025-07-14 10:56:48');
INSERT INTO `im_private_message` VALUES (171, 14, 15, '谢谢，我会尽快回来', 0, 1, '2025-07-14 10:56:48');
INSERT INTO `im_private_message` VALUES (172, 15, 14, '我们都会想你的', 0, 1, '2025-07-14 10:56:48');
INSERT INTO `im_private_message` VALUES (173, 14, 15, '我也想你们', 0, 1, '2025-07-14 10:56:48');
INSERT INTO `im_private_message` VALUES (174, 14, 15, '到上海了，酒店很不错', 0, 1, '2025-07-15 10:56:48');
INSERT INTO `im_private_message` VALUES (175, 15, 14, '那就好，开完会早点休息', 0, 1, '2025-07-15 10:56:48');
INSERT INTO `im_private_message` VALUES (176, 14, 15, '会议很顺利，明天回去', 0, 1, '2025-07-16 10:56:48');
INSERT INTO `im_private_message` VALUES (177, 15, 14, '太好了，我们等你回来', 0, 1, '2025-07-16 10:56:48');
