INSERT INTO `im_private_message` VALUES (179, 15, 14, '你真贴心，路上注意安全', 0, 1, '2025-07-16 10:56:48');
INSERT INTO `im_private_message` VALUES (180, 14, 15, '到家了，出租车已经在路上', 0, 1, '2025-07-17 10:56:48');
INSERT INTO `im_private_message` VALUES (181, 15, 14, '太好了，我们准备好晚餐等你', 0, 1, '2025-07-17 10:56:48');
