INSERT INTO `im_private_message` VALUES (197, 17, 14, '有的，我很乖', 0, 1, '2025-07-15 10:56:48');
INSERT INTO `im_private_message` VALUES (198, 14, 17, '真棒！爸爸给你带礼物', 0, 1, '2025-07-15 10:56:48');
INSERT INTO `im_private_message` VALUES (199, 17, 14, '是娃娃吗？', 0, 1, '2025-07-15 10:56:48');
